TWAIDriver canB(static_cast<gpio_num_t>(CAN_TX), static_cast<gpio_num_t>(CAN_RX));
uint32_t replayIndex = 0;
uint32_t lastReplayMs = 0;
bool replayDone = false;

void printFrame(const char *prefix, const CanFrame &frame)
{
    Serial.printf("%s CAN_B id=0x%03lX dlc=%u data=", prefix, static_cast<unsigned long>(frame.id), frame.dlc);
    for (uint8_t i = 0; i < frame.dlc && i < 8; ++i)
    {
        if (frame.data[i] < 16)
            Serial.print('0');
        Serial.print(frame.data[i], HEX);
        if (i + 1 < frame.dlc)
            Serial.print(' ');
    }
    Serial.println();
}

void sendNextReplayFrame()
{
    if (replayDone || millis() - lastReplayMs < 5)
        return;

    if (replayIndex >= REPLAY_FRAME_COUNT)
    {
        replayDone = true;
        Serial.println("Replay finished; continuing CAN_B RX logging");
        return;
    }

    ReplayFrame replay;
    memcpy_P(&replay, &REPLAY_FRAMES[replayIndex], sizeof(replay));

    CanFrame frame;
    frame.id = replay.id;
    frame.dlc = replay.dlc <= 8 ? replay.dlc : 8;
    memcpy(frame.data, replay.data, sizeof(frame.data));
    canB.send(frame);
    replayIndex++;
    lastReplayMs = millis();
}

void readCanB()
{
    CanFrame frame;
    while (canB.read(frame))
        printFrame("RX", frame);
}

void setup()
{
    Serial.begin(115200);
    delay(1000);
    setCanTxEnabled(true);
    if (!canB.init())
    {
        Serial.println("CAN_B init failed");
        return;
    }
    canB.setBusMode(CanBusMode::Normal);
    canB.setFilters(nullptr, 0);
    Serial.printf("CAN_B replay ready: %lu frames\n", static_cast<unsigned long>(REPLAY_FRAME_COUNT));
}

void loop()
{
    sendNextReplayFrame();
    readCanB();
    delay(1);
}
